  ('aboriginal-f0899a01-moex-00407', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依據原住民族委員會組織法，下列事項非由原住民族委員會掌理？', '["原住民族政策、制度、法規之綜合規劃、協調及推動", "原住民身分與原住民族之認定、部落之核定", "原住民運動人才之培育、規劃、協調及推動", "原住民健康促進、社會福利、工作權保障、就業服務、法律服務之規劃、協調及推動"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00408', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '原住民民族別的認定需經行政院核定，下列那一個民族尚未被政府列入法定原住民族？', '["撒奇萊雅族", "拉阿魯哇族", "馬卡道族", "卡那卡那富族"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00409', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '政府辦理原住民族經濟發展業務、輔導事業機構、住宅之興辦、租售、建購及修繕業務可由下列那一 種基金支應所需之經費？', '["原住民族文化事業基金", "原住民族綜合發展基金", "原住民族社會發展基金", "原住民族地區建設基金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00410', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '行政院為統合原住民族政策，保障原住民族權益，辦理原住民族業務，於1996年12月1日成立原住 民族委員會，依據原住民族委員會組織法，下列敘述何者錯誤？', '["設置主任委員1人，由原住民擔任", "設置副主任委員3人，其中2人應由原住民擔任", "設置委員19人至29人，其中原住民族各族代表應至少1人依聘用人員聘用條例聘用，且應有二分之 一以上人數具原住民身分，其聘期隨主任委員異動而更易", "原住民族委員會簡任、薦任、委任各官等人員具原住民身分者，均不得低於百分之七十"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00411', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依據原住民族語言發展法之規定，下列敘述何者錯誤？', '["原住民山地鄉、平地鄉之鄉公所，可以以該地區之原住民族語言書寫公文", "花蓮火車站可以使用阿美族、太魯閣族語進行播音", "為因應原住民學生學習的需求，花蓮的國民中小學可以以阿美族語或是太魯閣族語進行教學", "原住民至法院出庭陳述意見時，可以以原民族語言陳述意見，但需自行聘請通譯傳譯之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00412', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依據原住民族基本法，下列敘述何者錯誤？', '["原住民得在原住民族地區從事獵捕野生動物、採集野生植物、礦物、土石等營利行為", "當政府或私人於原住民族土地從事土地開發時，原住民族或部落得拒絕之", "當政府於原住民族地區劃設國家公園、國家級風景特定區、林業區、生態保育區時，原住民族得拒 絕之", "當政府欲於原住民族地區內存放有害物質時，原住民族得拒絕之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00413', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依據原住民族基本法，下列名詞定義，何者錯誤？', '["原住民族地區，係指原住民傳統居住，具有原住民族歷史淵源及文化特色，經中央原住民族主管機 關報請行政院核定之地區", "部落，係指原住民於原住民族地區一定區域內，依其傳統規範共同生活結合而成之團體，且經中央 原住民族主管機關核定者", "原住民族土地，係指原住民保留地", "原住民族，係指阿美族、泰雅族、排灣族、布農族、卑南族、魯凱族、鄒族、賽夏族、雅美族、邵 族、噶瑪蘭族、太魯閣族及其他自認為原住民族並經中央原住民族主管機關報請行政院核定之民族"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00414', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依據原住民身分法，下列何種情形不是原住民得申請喪失原住民身分之情形？', '["與非原住民結婚", "為非原住民收養", "未滿7歲之原住民為非原住民收養", "年滿20歲，自願拋棄之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00415', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依據原住民族基本法第21條之規定，政府或私人於原住民族土地或部落及其周邊一定範圍內之公有 土地從事某些事情時，應諮商並取得原住民族或部落同意或參與，下列那一個選項不包括之？', '["土地開發", "資源利用", "學術研究", "劃設生態保育區"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00416', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依據原住民保留地開發管理辦法，原住民申請無償取得原住民保留地所有權，土地面積最高限額，何 者正確？', '["依區域計畫法編定為農牧用地、養殖用地或依都市計畫法劃定為農業區、保護區，並供農作、養殖 或畜牧使用之土地，每人一公頃", "依區域計畫法編定為林業用地或依都市計畫法劃定為保護區並供作造林使用之土地，每人一公頃", "依法得為建築使用之土地，每戶一公頃", "其他用地，每戶一公頃"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
